/// <summary>
///
/// </summary>
[SysClientCacheDataMethodAttribute(true)]
public static str purchAgreementIdOrg()
{
    str purchIdOrg = SysComputedColumn::returnField(
    dataentityviewstr(VendProductReceiptLineV2Entity),
    dataEntityDataSourceStr(VendProductReceiptLineV2Entity, VendPackingSlipTrans),
    fieldStr(VendPackingSlipTrans, OrigPurchid));

    return strFmt(@"
    (select top 1 PURCHNUMBERSEQUENCE
     from AGREEMENTHEADER a
     join PURCHTABLE PT on PT.MatchingAgreement = a.RECID
     where PT.PurchId = %1)", purchIdOrg);


}
